steps.script:
() => {
  var out = { hasScript:false, klaviyoType:(typeof window.klaviyo), ss:{}, captured:[], url:location.href, title:document.title };
  try { out.hasScript = !!document.querySelector('script[src*="ml-source-capture"]'); } catch(e){ out.e1=String(e); }
  try { out.ss.ml_utms = sessionStorage.getItem('ml_utms'); out.ss.ml_landing = sessionStorage.getItem('ml_landing'); } catch(e){ out.e2=String(e); }
  var prev = window.klaviyo;
  try {
    window.klaviyo = { push:function(a){ out.captured.push(a); } };
    window.dispatchEvent(new CustomEvent('klaviyoForms', { detail:{ type:'submit', formId:'WpgHez' } }));
  } catch(e){ out.e3=String(e); }
  try { window.klaviyo = prev; } catch(e){}
  return out;
}
